package src.blocks.xmldb.org.apache.cocoon.generation;

public class XMLDBCollectionGenerator extends ServiceableGenerator implements CacheableProcessingComponent , Configurable , Initializable { protected static final String URI = "http://apache.org/cocoon/xmldb/1.0" ; protected static final String PREFIX = "collection" ; protected static final String RESOURCE_COUNT_ATTR = "resources" ; protected static final String COLLECTION_COUNT_ATTR = "collections" ; protected static final String COLLECTION = "collection" ; protected static final String QCOLLECTION = PREFIX + ":collection" ; protected static final String RESOURCE = "resource" ; protected static final String QRESOURCE = PREFIX + ":resource" ; protected String driver ; protected String base ; protected String col ; protected Database database ; protected Collection collection ; protected final AttributesImpl attributes = new AttributesImpl ( ) ; public void recycle ( ) { super . recycle ( ) ; this . col = null ; this . collection = null ; } public void configure ( Configuration conf ) throws ConfigurationException { this . driver = conf . getChild ( "driver" ) . getValue ( ) ; this . base = conf . getChild ( "base" ) . getValue ( ) ; } public void initialize ( ) throws Exception { try { Class c = Class . forName ( driver ) ; database = ( Database ) c . newInstance ( ) ; DatabaseManager . registerDatabase ( database ) ; } catch ( XMLDBException xde ) { getLogger ( ) . error ( "Unable to connect to the XML:DB database" ) ; throw new ProcessingException ( "Unable to connect to the XML DB" + xde . getMessage ( ) ) ; } catch ( Exception e ) { getLogger ( ) . error ( "There was a problem setting up the connection" ) ; getLogger ( ) . error ( "Make sure that your driver is available" ) ; throw new ProcessingException ( "Problem setting up the connection: " + e . getMessage ( ) ) ; } } public void setup ( SourceResolver resolver , Map objectModel , String src , Parameters par ) throws ProcessingException , SAXException , IOException { super . setup ( resolver , objectModel , src , par ) ; } public SourceValidity getValidity ( ) { return null ; } public java . io . Serializable getKey ( ) { return null ; } public void generate ( ) throws IOException , SAXException , ProcessingException { col = source ; try { collection = DatabaseManager . getCollection ( base + col ) ; if ( collection == null ) { throw new ResourceNotFoundException ( "Collection " + col + " not found" ) ; } collectionToSAX ( collection ) ; collection . close ( ) ; } catch ( XMLDBException xde ) { throw new ProcessingException ( "Unable to fetch content '" + source + "':" + xde . getMessage ( ) ) ; } catch ( NullPointerException npe ) { getLogger ( ) . error ( "The XML:DB driver raised an exception" ) ; getLogger ( ) . error ( "probably the document was not found" ) ; throw new ProcessingException ( "Null pointer exception while " + "retrieving document : " + npe . getMessage ( ) ) ; } } public void collectionToSAX ( Collection collection ) throws SAXException { String ncollections ; String nresources ; String [ ] resources ; String [ ] collections ; try { ncollections = Integer . toString ( collection . getChildCollectionCount ( ) ) ; nresources = Integer . toString ( collection . getResourceCount ( ) ) ; attributes . clear ( ) ; attributes . addAttribute ( "" , RESOURCE_COUNT_ATTR , RESOURCE_COUNT_ATTR , "CDATA" , nresources ) ; attributes . addAttribute ( "" , COLLECTION_COUNT_ATTR , COLLECTION_COUNT_ATTR , "CDATA" , ncollections ) ; collections = collection . listChildCollections ( ) ; resources = collection . listResources ( ) ; this . xmlConsumer . startDocument ( ) ; this . xmlConsumer . startPrefixMapping ( PREFIX , URI ) ; this . xmlConsumer . startElement ( URI , "collections" , "collection:collections" , attributes ) ; for ( int i = 0 ; i < collections . length ; i ++ ) { attributes . clear ( ) ; attributes . addAttribute ( "" , "name" , "name" , "CDATA" , collections [ i ] ) ; this . xmlConsumer . startElement ( URI , COLLECTION , QCOLLECTION , attributes ) ; this . xmlConsumer . endElement ( URI , COLLECTION , COLLECTION ) ; } for ( int i = 0 ; i < resources . length ; i ++ ) { attributes . clear ( ) ; attributes . addAttribute ( "" , "name" , "name" , "CDATA" , resources [ i ] ) ; this . xmlConsumer . startElement ( URI , RESOURCE , QRESOURCE , attributes ) ; this . xmlConsumer . endElement ( URI , RESOURCE , RESOURCE ) ; } this . xmlConsumer . endElement ( URI , "collections" , "collection:collections" ) ; this . xmlConsumer . endPrefixMapping ( PREFIX ) ; this . xmlConsumer . endDocument ( ) ; } catch ( XMLDBException xde ) { getLogger ( ) . warn ( "Collection listing failed: " + xde . getMessage ( ) ) ; throw new SAXException ( "Collection listing failed: " + xde . getMessage ( ) ) ; } } }